Using SHA-256 or any fast cryptographic hash for passwords is **NOT secure**. Fast hashes like MD5, SHA-1, and SHA-256 are designed for speed, making them vulnerable to brute-force attacks. Modern GPUs can compute billions of SHA-256 hashes per second.

**VULNERABLE CODE**:

```javascript
const crypto = require('crypto');
const express = require('express');

const app = express();
app.use(express.json());

// VULNERABLE: Using fast SHA-256 hash for passwords
function hashPassword(password) {
  return crypto.createHash('sha256').update(password).digest('hex');
}

app.post('/api/register', (req, res) => {
  const { username, password } = req.body;

  // DANGEROUS: No salt, fast hash algorithm
  const hashedPassword = hashPassword(password);

  // Store username and hashedPassword in database
  saveUser(username, hashedPassword);

  res.json({ message: 'User registered successfully' });
});

app.post('/api/login', (req, res) => {
  const { username, password } = req.body;
  const user = getUserByUsername(username);

  // VULNERABLE: Simple hash comparison
  if (user && user.password === hashPassword(password)) {
    res.json({ message: 'Login successful' });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});
```

**Attack Payload**:
```bash
# Using hashcat to crack SHA-256 hashed passwords
hashcat -m 1400 -a 0 hashes.txt rockyou.txt

# GPU can crack ~10 billion SHA-256 hashes/second
# Common 8-char password cracked in < 1 hour
```

**Why This Is Dangerous**:
- **No Salt**: Identical passwords produce identical hashes, enabling rainbow table attacks
- **Fast Algorithm**: SHA-256 is designed for speed (10+ billion hashes/sec on modern GPUs)
- **No Work Factor**: Cannot increase computation cost as hardware improves
- **Timing Attack**: Direct comparison leaks information about password correctness

**SECURE VERSION**:

```javascript
const bcrypt = require('bcrypt');
const express = require('express');

const app = express();
app.use(express.json());

const SALT_ROUNDS = 12; // Adjustable work factor (2^12 iterations)

async function hashPassword(password) {
  // bcrypt automatically generates a unique salt and embeds it in the hash
  return await bcrypt.hash(password, SALT_ROUNDS);
}

async function verifyPassword(password, hash) {
  // Constant-time comparison prevents timing attacks
  return await bcrypt.compare(password, hash);
}

app.post('/api/register', async (req, res) => {
  try {
    const { username, password } = req.body;

    // Validate password strength before hashing
    if (password.length < 12) {
      return res.status(400).json({ error: 'Password must be at least 12 characters' });
    }

    // SECURE: bcrypt with automatic salt and work factor
    const hashedPassword = await hashPassword(password);

    await saveUser(username, hashedPassword);
    res.json({ message: 'User registered successfully' });
  } catch (error) {
    console.error('Registration error:', error.message);
    res.status(500).json({ error: 'Registration failed' });
  }
});

app.post('/api/login', async (req, res) => {
  try {
    const { username, password } = req.body;
    const user = await getUserByUsername(username);

    // SECURE: Constant-time comparison via bcrypt.compare
    if (user && await verifyPassword(password, user.password)) {
      res.json({ message: 'Login successful' });
    } else {
      res.status(401).json({ error: 'Invalid credentials' });
    }
  } catch (error) {
    console.error('Login error:', error.message);
    res.status(500).json({ error: 'Login failed' });
  }
});
```

**Key Security Controls**:
- **bcrypt Algorithm**: Intentionally slow, designed for password hashing (~100ms per hash)
- **Automatic Salting**: Each password gets a unique 128-bit salt embedded in the hash
- **Adjustable Work Factor**: Can increase `SALT_ROUNDS` as hardware improves (each increment doubles time)
- **Constant-Time Comparison**: `bcrypt.compare` prevents timing attacks

Argon2 is indeed the winner of the 2015 Password Hashing Competition and is recommended by OWASP as the preferred algorithm. It's more resistant to GPU/ASIC attacks because it's memory-hard, not just CPU-hard like bcrypt.

**PRODUCTION PATTERN**:

```javascript
const argon2 = require('argon2');
const express = require('express');
const rateLimit = require('express-rate-limit');
const winston = require('winston');

const app = express();
app.use(express.json());

// Configure secure logging (no sensitive data)
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [new winston.transports.File({ filename: 'auth.log' })]
});

// Rate limiting for authentication endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many attempts, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Argon2id configuration (OWASP recommended)
const ARGON2_CONFIG = {
  type: argon2.argon2id,      // Hybrid: resistant to side-channel AND GPU attacks
  memoryCost: 65536,          // 64 MB memory requirement
  timeCost: 3,                // 3 iterations
  parallelism: 4,             // 4 parallel threads
  hashLength: 32,             // 256-bit output
  saltLength: 16              // 128-bit salt (auto-generated)
};

// Environment-specific tuning
if (process.env.NODE_ENV === 'production') {
  ARGON2_CONFIG.memoryCost = 131072;  // 128 MB in production
  ARGON2_CONFIG.timeCost = 4;         // More iterations
}

async function hashPassword(password) {
  try {
    return await argon2.hash(password, ARGON2_CONFIG);
  } catch (error) {
    logger.error('Password hashing failed', { error: error.message });
    throw new Error('Password processing failed');
  }
}

async function verifyPassword(password, hash) {
  try {
    // Constant-time verification built into argon2.verify
    const isValid = await argon2.verify(hash, password);

    // Check if rehashing is needed (algorithm upgrade)
    if (isValid && argon2.needsRehash(hash, ARGON2_CONFIG)) {
      return { valid: true, needsRehash: true };
    }

    return { valid: isValid, needsRehash: false };
  } catch (error) {
    // Invalid hash format or verification error
    logger.warn('Password verification error', { error: error.message });
    return { valid: false, needsRehash: false };
  }
}

// Password strength validation
function validatePasswordStrength(password) {
  const errors = [];

  if (password.length < 12) errors.push('Minimum 12 characters required');
  if (password.length > 128) errors.push('Maximum 128 characters allowed');
  if (!/[A-Z]/.test(password)) errors.push('At least one uppercase letter required');
  if (!/[a-z]/.test(password)) errors.push('At least one lowercase letter required');
  if (!/[0-9]/.test(password)) errors.push('At least one number required');
  if (!/[^A-Za-z0-9]/.test(password)) errors.push('At least one special character required');

  return errors;
}

app.post('/api/register', authLimiter, async (req, res) => {
  const startTime = Date.now();

  try {
    const { username, password, email } = req.body;

    // Input validation
    if (!username || !password || !email) {
      return res.status(400).json({ error: 'Missing required fields' });
    }

    // Password strength check
    const strengthErrors = validatePasswordStrength(password);
    if (strengthErrors.length > 0) {
      return res.status(400).json({ error: 'Password too weak', details: strengthErrors });
    }

    // Check for compromised passwords (integration with HaveIBeenPwned API)
    // Implementation omitted for brevity

    const hashedPassword = await hashPassword(password);
    await saveUser(username, email, hashedPassword);

    logger.info('User registered', {
      username,
      duration: Date.now() - startTime,
      ip: req.ip
    });

    res.status(201).json({ message: 'User registered successfully' });
  } catch (error) {
    logger.error('Registration failed', { error: error.message, ip: req.ip });
    res.status(500).json({ error: 'Registration failed' });
  }
});

app.post('/api/login', authLimiter, async (req, res) => {
  const startTime = Date.now();

  try {
    const { username, password } = req.body;
    const user = await getUserByUsername(username);

    // IMPORTANT: Always perform hash comparison even if user doesn't exist
    // This prevents user enumeration via timing attacks
    const dummyHash = '$argon2id$v=19$m=65536,t=3,p=4$c29tZXNhbHQ$RdescudvJCsgt3ub+b+dWRWJTmaaJObG';
    const hashToVerify = user ? user.password : dummyHash;

    const { valid, needsRehash } = await verifyPassword(password, hashToVerify);

    if (user && valid) {
      // Transparent rehashing if algorithm parameters changed
      if (needsRehash) {
        const newHash = await hashPassword(password);
        await updateUserPassword(user.id, newHash);
        logger.info('Password rehashed', { userId: user.id });
      }

      logger.info('Login successful', {
        userId: user.id,
        duration: Date.now() - startTime,
        ip: req.ip
      });

      // Generate session/JWT token here
      res.json({ message: 'Login successful' });
    } else {
      logger.warn('Login failed', {
        username,
        duration: Date.now() - startTime,
        ip: req.ip
      });

      res.status(401).json({ error: 'Invalid credentials' });
    }
  } catch (error) {
    logger.error('Login error', { error: error.message, ip: req.ip });
    res.status(500).json({ error: 'Login failed' });
  }
});

module.exports = app;
```

**Defense in Depth Layers**:

1. **Algorithm Selection (Argon2id)**:
```javascript
// Argon2id combines Argon2i (side-channel resistant) and Argon2d (GPU resistant)
const config = {
  type: argon2.argon2id,  // MUST use argon2id, not argon2i or argon2d alone
  memoryCost: 65536,      // Forces 64MB memory allocation per hash
};
```

2. **Transparent Rehashing**:
```javascript
// Automatically upgrade hashes when security parameters change
if (argon2.needsRehash(hash, ARGON2_CONFIG)) {
  const newHash = await hashPassword(password);
  await updateUserPassword(userId, newHash);
}
```

3. **User Enumeration Prevention**:
```javascript
// Always perform hash verification to prevent timing-based user enumeration
const dummyHash = '$argon2id$v=19$m=65536,t=3,p=4$...';
const hashToVerify = user ? user.password : dummyHash;
await verifyPassword(password, hashToVerify); // Always runs
```

**Additional Protections**:
- **Rate Limiting**: 5 login attempts per 15 minutes prevents brute force
- **Password Length Cap**: Maximum 128 chars prevents DoS via extremely long passwords
- **Audit Logging**: All auth events logged with IP, duration (without passwords)
- **Compromised Password Check**: Integration with HaveIBeenPwned k-Anonymity API
- **Memory Hardness**: 64-128MB requirement makes GPU attacks economically infeasible
- **Gradual Parameter Upgrade**: `needsRehash` enables seamless security improvements

You're absolutely right to be concerned - MD5 is completely broken for password hashing. In the 2023 LastPass breach, attackers were able to crack user passwords offline because even though PBKDF2 was used, insufficient iterations made it vulnerable. MD5 is exponentially worse - it can be cracked at billions of hashes per second.

**VULNERABLE CODE**:

```java
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.Base64;

public class InsecurePasswordService {

    public String hashPassword(String password) {
        try {
            // VULNERABLE: MD5 is cryptographically broken
            MessageDigest md = MessageDigest.getInstance("MD5");
            byte[] digest = md.digest(password.getBytes());
            return Base64.getEncoder().encodeToString(digest);
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException("MD5 not available", e);
        }
    }

    public boolean verifyPassword(String password, String storedHash) {
        String inputHash = hashPassword(password);
        // VULNERABLE: Timing attack possible with equals()
        return inputHash.equals(storedHash);
    }

    // Also vulnerable: SHA-1 or SHA-256 without salt or iterations
    public String hashWithSha256(String password) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] digest = md.digest(password.getBytes());
            return Base64.getEncoder().encodeToString(digest);
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }
}
```

**Attack Payload**:
```bash
# Using hashcat to crack MD5 passwords at 50+ billion hashes/second
hashcat -m 0 -a 0 hashes.txt rockyou.txt

# Rainbow table attack - instant lookup for unsalted hashes
rcrack /path/to/tables -h 5d41402abc4b2a76b9719d911017c592

# Even SHA-256 without salt can be cracked via precomputed tables
hashcat -m 1400 -a 0 sha256_hashes.txt wordlist.txt
```

**Why This Is Dangerous**:
- MD5 can be computed at 50+ billion hashes/second on modern GPUs
- No salt means identical passwords produce identical hashes, enabling rainbow table attacks
- No iterations/work factor means brute-force is trivial
- Single hash algorithms (MD5, SHA-1, SHA-256) are designed for speed, not password storage
- Timing attacks on string comparison leak password information

**SECURE VERSION**:

```java
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import java.security.MessageDigest;

public class SecurePasswordService {

    // BCrypt with cost factor 12 (4096 iterations)
    // Automatically handles salt generation and storage
    private final PasswordEncoder passwordEncoder;

    public SecurePasswordService() {
        // Cost factor 12 = 2^12 = 4096 iterations
        // Each increment doubles the computation time
        this.passwordEncoder = new BCryptPasswordEncoder(12);
    }

    public String hashPassword(String password) {
        // BCrypt generates unique salt per password
        // Format: $2a$12$[22-char-salt][31-char-hash]
        return passwordEncoder.encode(password);
    }

    public boolean verifyPassword(String rawPassword, String storedHash) {
        // BCrypt.matches() is constant-time to prevent timing attacks
        // Extracts salt from stored hash automatically
        return passwordEncoder.matches(rawPassword, storedHash);
    }

    // Constant-time comparison to prevent timing attacks
    private boolean constantTimeEquals(byte[] a, byte[] b) {
        return MessageDigest.isEqual(a, b);
    }
}
```

**Key Security Controls**:
- **BCrypt with adequate work factor**: Cost factor 12+ makes brute-force computationally expensive (~300ms per hash)
- **Automatic unique salt per password**: Defeats rainbow tables and ensures identical passwords produce different hashes
- **Constant-time comparison**: BCrypt.matches() prevents timing side-channel attacks
- **Adaptive algorithm**: Work factor can be increased over time as hardware improves

Excellent questions! Argon2 won the Password Hashing Competition in 2015 and is now considered the gold standard - it's memory-hard, making it resistant to GPU and ASIC attacks that can crack BCrypt faster. For migration, you need a gradual strategy that upgrades hashes on successful login.

**PRODUCTION PATTERN**:

```java
import de.mkammerer.argon2.Argon2;
import de.mkammerer.argon2.Argon2Factory;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.util.Base64;

public class ProductionPasswordService {

    private static final Logger logger = LoggerFactory.getLogger(ProductionPasswordService.class);
    private static final Logger securityAudit = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Argon2id - hybrid variant resistant to side-channel and GPU attacks
    private final Argon2 argon2;
    private final BCryptPasswordEncoder bcrypt;

    // Argon2 parameters (OWASP recommended for 2024)
    private static final int ARGON2_ITERATIONS = 3;
    private static final int ARGON2_MEMORY_KB = 65536;  // 64 MB
    private static final int ARGON2_PARALLELISM = 4;
    private static final int ARGON2_HASH_LENGTH = 32;

    // Hash format prefixes for algorithm identification
    private static final String PREFIX_ARGON2 = "$argon2id$";
    private static final String PREFIX_BCRYPT = "$2a$";
    private static final String PREFIX_LEGACY_MD5 = "$md5$";

    public ProductionPasswordService() {
        this.argon2 = Argon2Factory.create(Argon2Factory.Argon2Types.ARGON2id);
        this.bcrypt = new BCryptPasswordEncoder(12);
    }

    /**
     * Hash new passwords with Argon2id
     */
    public String hashPassword(String password) {
        try {
            String hash = argon2.hash(
                ARGON2_ITERATIONS,
                ARGON2_MEMORY_KB,
                ARGON2_PARALLELISM,
                password.toCharArray()
            );

            logger.debug("Password hashed with Argon2id");
            return hash;

        } finally {
            // Clear password from memory
            argon2.wipeArray(password.toCharArray());
        }
    }

    /**
     * Verify password and transparently upgrade legacy hashes
     * Returns PasswordVerificationResult with upgrade flag
     */
    public PasswordVerificationResult verifyAndUpgrade(
            String rawPassword, 
            String storedHash,
            String userId) {

        boolean verified = false;
        boolean needsUpgrade = false;
        String newHash = null;

        try {
            if (storedHash.startsWith(PREFIX_ARGON2)) {
                // Current algorithm - verify directly
                verified = argon2.verify(storedHash, rawPassword.toCharArray());

            } else if (storedHash.startsWith(PREFIX_BCRYPT)) {
                // BCrypt - verify and flag for upgrade
                verified = bcrypt.matches(rawPassword, storedHash);
                needsUpgrade = verified;

                securityAudit.info("BCrypt hash verified for user {}, upgrade pending", userId);

            } else if (storedHash.startsWith(PREFIX_LEGACY_MD5)) {
                // Legacy MD5 - verify and MUST upgrade
                verified = verifyLegacyMd5(rawPassword, storedHash);
                needsUpgrade = verified;

                securityAudit.warn(
                    "CRITICAL: Legacy MD5 hash verified for user {}, immediate upgrade required",
                    userId
                );
            } else {
                // Unknown format
                securityAudit.error("Unknown hash format for user {}", userId);
                return new PasswordVerificationResult(false, false, null);
            }

            // Generate upgraded hash if verification succeeded
            if (verified && needsUpgrade) {
                newHash = hashPassword(rawPassword);
                logger.info("Generated upgraded Argon2id hash for user {}", userId);
            }

            // Audit logging
            if (verified) {
                securityAudit.info("Password verification SUCCESS for user {}", userId);
            } else {
                securityAudit.warn("Password verification FAILED for user {}", userId);
            }

            return new PasswordVerificationResult(verified, needsUpgrade, newHash);

        } catch (Exception e) {
            logger.error("Password verification error for user {}", userId, e);
            securityAudit.error("Password verification ERROR for user {}: {}", userId, e.getMessage());
            return new PasswordVerificationResult(false, false, null);
        }
    }

    /**
     * Verify legacy MD5 hash (for migration only)
     */
    private boolean verifyLegacyMd5(String password, String storedHash) {
        try {
            // Extract salt and hash from stored format: $md5$[salt]$[hash]
            String[] parts = storedHash.split("\\$");
            if (parts.length != 4) return false;

            String salt = parts[2];
            String expectedHash = parts[3];

            MessageDigest md = MessageDigest.getInstance("MD5");
            md.update(salt.getBytes());
            byte[] digest = md.digest(password.getBytes());
            String computedHash = Base64.getEncoder().encodeToString(digest);

            // Constant-time comparison
            return MessageDigest.isEqual(
                expectedHash.getBytes(),
                computedHash.getBytes()
            );

        } catch (NoSuchAlgorithmException e) {
            return false;
        }
    }

    /**
     * Check if stored hash needs upgrade based on algorithm or parameters
     */
    public boolean needsRehash(String storedHash) {
        if (!storedHash.startsWith(PREFIX_ARGON2)) {
            return true;  // Not Argon2id
        }

        // Check if Argon2 parameters are current
        // Hash format: $argon2id$v=19$m=65536,t=3,p=4$[salt]$[hash]
        return !storedHash.contains("m=" + ARGON2_MEMORY_KB) ||
               !storedHash.contains("t=" + ARGON2_ITERATIONS) ||
               !storedHash.contains("p=" + ARGON2_PARALLELISM);
    }

    /**
     * Result object for password verification with upgrade info
     */
    public static class PasswordVerificationResult {
        private final boolean verified;
        private final boolean needsUpgrade;
        private final String upgradedHash;

        public PasswordVerificationResult(boolean verified, boolean needsUpgrade, String upgradedHash) {
            this.verified = verified;
            this.needsUpgrade = needsUpgrade;
            this.upgradedHash = upgradedHash;
        }

        public boolean isVerified() { return verified; }
        public boolean needsUpgrade() { return needsUpgrade; }
        public String getUpgradedHash() { return upgradedHash; }
    }
}
```

**Defense in Depth Layers**:

1. **Algorithm Selection - Argon2id**:
```java
// Argon2id is memory-hard, preventing GPU/ASIC acceleration
// Parameters calibrated for ~500ms verification time
private static final int ARGON2_MEMORY_KB = 65536;  // 64 MB per hash
private static final int ARGON2_ITERATIONS = 3;     // Time cost
private static final int ARGON2_PARALLELISM = 4;    // CPU threads
```

2. **Transparent Hash Migration**:
```java
// In your authentication service
public boolean authenticate(String username, String password) {
    User user = userRepository.findByUsername(username);
    PasswordVerificationResult result = passwordService.verifyAndUpgrade(
        password, user.getPasswordHash(), user.getId()
    );

    if (result.isVerified() && result.needsUpgrade()) {
        // Upgrade hash in background - don't block authentication
        userRepository.updatePasswordHash(user.getId(), result.getUpgradedHash());
        auditLog.info("Password hash upgraded for user {}", user.getId());
    }

    return result.isVerified();
}
```

3. **Parameter Rotation Support**:
```java
// Configuration-driven parameters for easy rotation
@ConfigurationProperties(prefix = "security.password")
public class PasswordConfig {
    private int argon2Memory = 65536;
    private int argon2Iterations = 3;
    private int argon2Parallelism = 4;

    // Automatically flag hashes with old parameters for upgrade
    public boolean isCurrentConfig(String hash) {
        return hash.contains("m=" + argon2Memory) &&
               hash.contains("t=" + argon2Iterations);
    }
}
```

**Additional Protections**:
- **Memory wiping**: Clear password char arrays after use to prevent memory dumps
- **Pepper support**: Add application-level secret for additional protection (store in HSM/vault)
- **Rate limiting**: Prevent brute-force at the application layer
- **Breach detection**: Monitor for credential stuffing patterns
- **Gradual migration**: Don't force all users to reset - upgrade on next login
- **Audit trail**: Log all password operations for security monitoring
- **Parameter benchmarking**: Calibrate Argon2 parameters for your hardware (~500ms target)

SHA256 is **NOT** suitable for password hashing. While SHA256 is a cryptographically secure hash function, it's designed for speed - exactly the opposite of what you want for passwords. Modern GPUs can compute billions of SHA256 hashes per second, making brute-force attacks trivial.

**VULNERABLE CODE**:

```go
package main

import (
	"crypto/sha256"
	"database/sql"
	"encoding/hex"
	"net/http"

	_ "github.com/lib/pq"
)

var db *sql.DB

// VULNERABLE: Using SHA256 for password hashing
func hashPassword(password string) string {
	hash := sha256.Sum256([]byte(password))
	return hex.EncodeToString(hash[:])
}

func registerUser(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	password := r.FormValue("password")

	// VULNERABLE: Fast hash, no salt, easily cracked
	hashedPassword := hashPassword(password)

	_, err := db.Exec(
		"INSERT INTO users (username, password_hash) VALUES ($1, $2)",
		username, hashedPassword,
	)
	if err != nil {
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusCreated)
}

func loginUser(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	password := r.FormValue("password")

	// VULNERABLE: Compare fast hashes
	inputHash := hashPassword(password)

	var storedHash string
	err := db.QueryRow(
		"SELECT password_hash FROM users WHERE username = $1",
		username,
	).Scan(&storedHash)

	if err != nil || inputHash != storedHash {
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	w.Write([]byte("Login successful"))
}
```

**Attack Scenario**:
```bash
# Using Hashcat to crack SHA256 password hashes
# Speed: ~10 billion hashes/second on modern GPU
hashcat -m 1400 -a 0 hashes.txt rockyou.txt

# Rainbow table attack (precomputed hashes)
# Instant lookup for common passwords
```

**Why This Is Dangerous**:
- **Speed**: SHA256 computes ~10 billion hashes/second on GPU - an 8-character password cracks in minutes
- **No salt**: Identical passwords produce identical hashes, enabling rainbow table attacks
- **No work factor**: Cannot increase computational cost as hardware improves
- **Not memory-hard**: GPU parallelization makes cracking trivially scalable

**SECURE VERSION**:

```go
package main

import (
	"database/sql"
	"log"
	"net/http"

	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

var db *sql.DB

const (
	// bcrypt cost factor: 2^12 = 4096 iterations
	// Adjust based on server hardware (target ~250ms per hash)
	bcryptCost = 12
)

// SECURE: Using bcrypt with automatic salting
func hashPassword(password string) (string, error) {
	// bcrypt automatically generates a unique salt per password
	// and embeds it in the resulting hash string
	hash, err := bcrypt.GenerateFromPassword([]byte(password), bcryptCost)
	if err != nil {
		return "", err
	}
	return string(hash), nil
}

// SECURE: Constant-time comparison built into bcrypt
func verifyPassword(password, hashedPassword string) bool {
	err := bcrypt.CompareHashAndPassword([]byte(hashedPassword), []byte(password))
	return err == nil
}

func registerUser(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	password := r.FormValue("password")

	// Validate password strength before hashing
	if len(password) < 8 {
		http.Error(w, "Password must be at least 8 characters", http.StatusBadRequest)
		return
	}

	// SECURE: bcrypt with cost factor and automatic salt
	hashedPassword, err := hashPassword(password)
	if err != nil {
		log.Printf("Password hashing error: %v", err)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	_, err = db.Exec(
		"INSERT INTO users (username, password_hash) VALUES ($1, $2)",
		username, hashedPassword,
	)
	if err != nil {
		log.Printf("Database error: %v", err)
		http.Error(w, "Registration failed", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusCreated)
}

func loginUser(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	password := r.FormValue("password")

	var storedHash string
	err := db.QueryRow(
		"SELECT password_hash FROM users WHERE username = $1",
		username,
	).Scan(&storedHash)

	if err != nil {
		// SECURE: Same response for user not found vs wrong password
		// Prevents username enumeration
		bcrypt.CompareHashAndPassword([]byte("$2a$12$dummy"), []byte(password))
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	// SECURE: Constant-time comparison prevents timing attacks
	if !verifyPassword(password, storedHash) {
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	w.Write([]byte("Login successful"))
}
```

**Key Security Controls**:
- **bcrypt algorithm**: Purpose-built for password hashing with adjustable work factor
- **Automatic salting**: Each password gets unique 128-bit salt, defeating rainbow tables
- **Cost factor**: 2^12 iterations makes each hash take ~250ms, limiting brute-force to ~4 attempts/second
- **Constant-time comparison**: Built into bcrypt.CompareHashAndPassword, prevents timing attacks
- **Timing-safe error handling**: Dummy hash comparison when user not found prevents enumeration

Excellent questions! Argon2 is indeed the current gold standard - it won the Password Hashing Competition in 2015 and is recommended by OWASP. It's memory-hard, which means it requires significant RAM to compute, making GPU/ASIC attacks much more expensive. Here's a production-ready implementation with transparent hash upgrades.

**PRODUCTION PATTERN**:

```go
package auth

import (
	"crypto/rand"
	"crypto/subtle"
	"database/sql"
	"encoding/base64"
	"errors"
	"fmt"
	"log"
	"strings"
	"sync"
	"time"

	"golang.org/x/crypto/argon2"
	"golang.org/x/crypto/bcrypt"
)

// Argon2id parameters (OWASP recommended)
type Argon2Params struct {
	Memory      uint32 // Memory in KiB
	Iterations  uint32 // Time cost
	Parallelism uint8  // Threads
	SaltLength  uint32 // Salt size in bytes
	KeyLength   uint32 // Output hash length
}

var (
	// Current production parameters - adjust based on server resources
	// Target: ~500ms hash time on production hardware
	CurrentParams = Argon2Params{
		Memory:      64 * 1024, // 64 MiB
		Iterations:  3,
		Parallelism: 4,
		SaltLength:  16,
		KeyLength:   32,
	}

	// Minimum acceptable parameters (for legacy hash detection)
	MinParams = Argon2Params{
		Memory:      32 * 1024,
		Iterations:  2,
		Parallelism: 2,
		SaltLength:  16,
		KeyLength:   32,
	}

	ErrInvalidHash     = errors.New("invalid hash format")
	ErrWeakParameters  = errors.New("hash parameters below minimum threshold")
	ErrPasswordTooLong = errors.New("password exceeds maximum length")
)

type PasswordService struct {
	db            *sql.DB
	params        Argon2Params
	logger        *log.Logger
	upgradeMutex  sync.Mutex
	metricsClient MetricsClient
}

type MetricsClient interface {
	Increment(metric string, tags map[string]string)
	Timing(metric string, duration time.Duration, tags map[string]string)
}

func NewPasswordService(db *sql.DB, logger *log.Logger, metrics MetricsClient) *PasswordService {
	return &PasswordService{
		db:            db,
		params:        CurrentParams,
		logger:        logger,
		metricsClient: metrics,
	}
}

// HashPassword creates an Argon2id hash with the current parameters
func (ps *PasswordService) HashPassword(password string) (string, error) {
	start := time.Now()
	defer func() {
		ps.metricsClient.Timing("password.hash.duration", time.Since(start), nil)
	}()

	// SECURITY: Limit password length to prevent DoS
	// Argon2 processes entire input, very long passwords = high CPU
	if len(password) > 72 {
		return "", ErrPasswordTooLong
	}

	// Generate cryptographically secure random salt
	salt := make([]byte, ps.params.SaltLength)
	if _, err := rand.Read(salt); err != nil {
		return "", fmt.Errorf("failed to generate salt: %w", err)
	}

	// Argon2id: Hybrid version resistant to both side-channel and GPU attacks
	hash := argon2.IDKey(
		[]byte(password),
		salt,
		ps.params.Iterations,
		ps.params.Memory,
		ps.params.Parallelism,
		ps.params.KeyLength,
	)

	// Encode in PHC string format for self-describing storage
	// Format: $argon2id$v=19$m=65536,t=3,p=4$salt$hash
	encodedHash := fmt.Sprintf(
		"$argon2id$v=%d$m=%d,t=%d,p=%d$%s$%s",
		argon2.Version,
		ps.params.Memory,
		ps.params.Iterations,
		ps.params.Parallelism,
		base64.RawStdEncoding.EncodeToString(salt),
		base64.RawStdEncoding.EncodeToString(hash),
	)

	return encodedHash, nil
}

// VerifyPassword checks password and returns whether rehashing is needed
func (ps *PasswordService) VerifyPassword(password, encodedHash string) (match bool, needsRehash bool, err error) {
	start := time.Now()
	defer func() {
		ps.metricsClient.Timing("password.verify.duration", time.Since(start), nil)
	}()

	// Detect hash type for migration support
	switch {
	case strings.HasPrefix(encodedHash, "$argon2id$"):
		return ps.verifyArgon2(password, encodedHash)
	case strings.HasPrefix(encodedHash, "$2a$") || strings.HasPrefix(encodedHash, "$2b$"):
		return ps.verifyBcrypt(password, encodedHash)
	default:
		ps.logger.Printf("SECURITY: Unknown hash format detected")
		return false, false, ErrInvalidHash
	}
}

func (ps *PasswordService) verifyArgon2(password, encodedHash string) (bool, bool, error) {
	// Parse the PHC string format
	parts := strings.Split(encodedHash, "$")
	if len(parts) != 6 {
		return false, false, ErrInvalidHash
	}

	var version int
	var memory, iterations uint32
	var parallelism uint8

	_, err := fmt.Sscanf(parts[2], "v=%d", &version)
	if err != nil {
		return false, false, ErrInvalidHash
	}

	_, err = fmt.Sscanf(parts[3], "m=%d,t=%d,p=%d", &memory, &iterations, &parallelism)
	if err != nil {
		return false, false, ErrInvalidHash
	}

	salt, err := base64.RawStdEncoding.DecodeString(parts[4])
	if err != nil {
		return false, false, ErrInvalidHash
	}

	expectedHash, err := base64.RawStdEncoding.DecodeString(parts[5])
	if err != nil {
		return false, false, ErrInvalidHash
	}

	// Compute hash with same parameters
	computedHash := argon2.IDKey(
		[]byte(password),
		salt,
		iterations,
		memory,
		parallelism,
		uint32(len(expectedHash)),
	)

	// SECURITY: Constant-time comparison prevents timing attacks
	match := subtle.ConstantTimeCompare(computedHash, expectedHash) == 1

	// Check if parameters need upgrading
	needsRehash := memory < ps.params.Memory ||
		iterations < ps.params.Iterations ||
		parallelism < ps.params.Parallelism

	if needsRehash && match {
		ps.metricsClient.Increment("password.rehash.needed", map[string]string{
			"reason": "weak_params",
		})
	}

	return match, needsRehash, nil
}

func (ps *PasswordService) verifyBcrypt(password, encodedHash string) (bool, bool, error) {
	// Legacy bcrypt support - always needs rehash to Argon2
	err := bcrypt.CompareHashAndPassword([]byte(encodedHash), []byte(password))
	if err != nil {
		return false, false, nil
	}

	ps.metricsClient.Increment("password.rehash.needed", map[string]string{
		"reason": "legacy_bcrypt",
	})

	// Match successful, but always upgrade from bcrypt
	return true, true, nil
}

// AuthenticateAndUpgrade handles login with transparent hash upgrades
func (ps *PasswordService) AuthenticateAndUpgrade(userID int64, password string) error {
	var storedHash string
	err := ps.db.QueryRow(
		"SELECT password_hash FROM users WHERE id = $1",
		userID,
	).Scan(&storedHash)

	if err == sql.ErrNoRows {
		// SECURITY: Prevent timing-based user enumeration
		// Always perform a hash operation even for non-existent users
		_, _ = ps.HashPassword(password)
		return errors.New("invalid credentials")
	}
	if err != nil {
		ps.logger.Printf("Database error during auth: %v", err)
		return errors.New("authentication failed")
	}

	match, needsRehash, err := ps.VerifyPassword(password, storedHash)
	if err != nil {
		ps.logger.Printf("Hash verification error: %v", err)
		return errors.New("authentication failed")
	}

	if !match {
		ps.metricsClient.Increment("auth.failed", nil)
		return errors.New("invalid credentials")
	}

	// Transparent hash upgrade on successful login
	if needsRehash {
		go ps.upgradeHash(userID, password)
	}

	ps.metricsClient.Increment("auth.success", nil)
	return nil
}

// upgradeHash performs async hash upgrade (non-blocking)
func (ps *PasswordService) upgradeHash(userID int64, password string) {
	ps.upgradeMutex.Lock()
	defer ps.upgradeMutex.Unlock()

	newHash, err := ps.HashPassword(password)
	if err != nil {
		ps.logger.Printf("Failed to generate new hash for user %d: %v", userID, err)
		return
	}

	_, err = ps.db.Exec(
		"UPDATE users SET password_hash = $1, hash_upgraded_at = NOW() WHERE id = $2",
		newHash, userID,
	)
	if err != nil {
		ps.logger.Printf("Failed to upgrade hash for user %d: %v", userID, err)
		return
	}

	ps.logger.Printf("Successfully upgraded password hash for user %d", userID)
	ps.metricsClient.Increment("password.rehash.completed", nil)
}
```

**Defense in Depth Layers**:

1. **Algorithm Selection (Argon2id)**:
```go
// Argon2id combines Argon2i (side-channel resistant) and Argon2d (GPU resistant)
hash := argon2.IDKey(password, salt, iterations, memory, parallelism, keyLength)
// Memory-hard: 64MB RAM required per hash attempt
// GPU attack cost: ~$1M to crack a single strong password
```

2. **Constant-Time Comparison**:
```go
// NEVER use == for hash comparison (timing attack vulnerable)
// BAD: computedHash == expectedHash
// GOOD: Uses same time regardless of where mismatch occurs
match := subtle.ConstantTimeCompare(computedHash, expectedHash) == 1
```

3. **Transparent Hash Migration**:
```go
// Detect legacy hashes and upgrade on successful login
if strings.HasPrefix(hash, "$2a$") {
    // bcrypt detected - verify then upgrade to Argon2
    if match {
        go upgradeToArgon2(userID, password)
    }
}
```

**Additional Protections**:

- **Password length limit (72 bytes)**: Prevents DoS via extremely long passwords that consume excessive CPU/memory
- **Self-describing hash format (PHC)**: Parameters stored with hash enable future upgrades without breaking existing passwords
- **Async hash upgrades**: Non-blocking upgrades don't impact login response time
- **Timing-safe user enumeration protection**: Always perform hash operation even for non-existent users
- **Metrics and monitoring**: Track hash upgrade progress, authentication failures, and timing for security analysis
- **Mutex for upgrades**: Prevents race conditions during concurrent hash upgrades for same user

