Using MD5 or SHA256 directly for password hashing is critically dangerous. These are fast hashing algorithms designed for integrity verification, NOT for password storage. Modern GPUs can compute billions of SHA256 hashes per second, making brute-force attacks trivial.

**VULNERABLE CODE**:

```csharp
using System;
using System.Security.Cryptography;
using System.Text;

namespace VulnerableAuth
{
    public class InsecurePasswordService
    {
        // VULNERABLE: Using MD5 - cryptographically broken
        public string HashPasswordMD5(string password)
        {
            using (MD5 md5 = MD5.Create())
            {
                byte[] inputBytes = Encoding.UTF8.GetBytes(password);
                byte[] hashBytes = md5.ComputeHash(inputBytes);
                return Convert.ToHexString(hashBytes).ToLower();
            }
        }

        // VULNERABLE: Using SHA256 without salt - too fast, rainbow table attacks
        public string HashPasswordSHA256(string password)
        {
            using (SHA256 sha256 = SHA256.Create())
            {
                byte[] inputBytes = Encoding.UTF8.GetBytes(password);
                byte[] hashBytes = sha256.ComputeHash(inputBytes);
                return Convert.ToHexString(hashBytes).ToLower();
            }
        }

        // VULNERABLE: SHA256 with weak static salt
        public string HashPasswordWithWeakSalt(string password)
        {
            string staticSalt = "MySecretSalt123"; // Same salt for all users!
            using (SHA256 sha256 = SHA256.Create())
            {
                byte[] inputBytes = Encoding.UTF8.GetBytes(password + staticSalt);
                byte[] hashBytes = sha256.ComputeHash(inputBytes);
                return Convert.ToHexString(hashBytes).ToLower();
            }
        }
