```

**Attack Scenario**:
```text
Attacker obtains database dump with MD5/SHA256 hashed passwords:
e99a18c428cb38d5f260853678922e03  (MD5 of "abc123")

Using hashcat on modern GPU (RTX 4090):
- MD5: ~150 billion hashes/second
- SHA256: ~25 billion hashes/second

Time to crack common 8-char passwords: seconds to minutes
```

**Why This Is Dangerous**:
- MD5 is cryptographically broken with known collision attacks
- SHA256 is too fast - GPUs can brute-force billions of hashes per second
- No salt means identical passwords produce identical hashes (rainbow tables)
- Static salt means one cracked password reveals the salt for all users
- No key stretching means no protection against GPU acceleration

**SECURE VERSION**:

```csharp
using System;
using System.Security.Cryptography;
using Microsoft.AspNetCore.Cryptography.KeyDerivation;

namespace SecureAuth
{
    public class SecurePasswordService
    {
        // Minimum iterations - adjust based on server performance
        // Target: 100-250ms hash time on your hardware
        private const int Iterations = 600000; // OWASP 2023 recommendation for PBKDF2-SHA256
        private const int SaltSize = 32; // 256 bits
        private const int HashSize = 32; // 256 bits

        public string HashPassword(string password)
        {
            // Generate cryptographically secure random salt
            byte[] salt = RandomNumberGenerator.GetBytes(SaltSize);

            // Use PBKDF2 with SHA256 - designed for password hashing
            byte[] hash = KeyDerivation.Pbkdf2(
                password: password,
                salt: salt,
                prf: KeyDerivationPrf.HMACSHA256,
                iterationCount: Iterations,
                numBytesRequested: HashSize
            );

            // Format: iterations.salt.hash (all base64)
            return $"{Iterations}.{Convert.ToBase64String(salt)}.{Convert.ToBase64String(hash)}";
        }

        public bool VerifyPassword(string password, string storedHash)
        {
            try
            {
                string[] parts = storedHash.Split('.');
                if (parts.Length != 3)
                    return false;

                int iterations = int.Parse(parts[0]);
                byte[] salt = Convert.FromBase64String(parts[1]);
                byte[] storedHashBytes = Convert.FromBase64String(parts[2]);

                byte[] computedHash = KeyDerivation.Pbkdf2(
                    password: password,
                    salt: salt,
                    prf: KeyDerivationPrf.HMACSHA256,
                    iterationCount: iterations,
                    numBytesRequested: storedHashBytes.Length
                );

                // Constant-time comparison prevents timing attacks
                return CryptographicOperations.FixedTimeEquals(computedHash, storedHashBytes);
            }
            catch
            {
                return false; // Fail securely on any parsing error
            }
        }
    }
}
```

**Key Security Controls**:
- **PBKDF2 with high iterations**: 600,000+ iterations makes brute-force computationally expensive (~250ms per hash on server)
- **Unique random salt per password**: Each password gets a cryptographically random 256-bit salt, defeating rainbow tables
- **Constant-time comparison**: `FixedTimeEquals` prevents timing side-channel attacks
- **Iteration count stored with hash**: Allows future upgrades without breaking existing passwords

Excellent questions! Argon2 is the Password Hashing Competition winner and is considered the gold standard. BCrypt is also excellent and battle-tested. For production systems, you need a migration strategy to upgrade legacy hashes transparently.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Security.Cryptography;
using System.Threading.Tasks;
using Konscious.Security.Cryptography;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace ProductionAuth
{
    public class PasswordHashingOptions
    {
        public int Argon2MemorySize { get; set; } = 65536; // 64 MB
        public int Argon2Iterations { get; set; } = 4;
        public int Argon2Parallelism { get; set; } = 4;
        public int SaltSize { get; set; } = 32;
        public int HashSize { get; set; } = 32;
        public int MinimumPBKDF2Iterations { get; set; } = 600000;
    }

    public enum HashAlgorithmType
    {
        Unknown = 0,
        MD5Legacy = 1,      // Dangerous - migrate immediately
        SHA256Legacy = 2,   // Dangerous - migrate immediately  
        PBKDF2 = 3,         // Acceptable with high iterations
        Argon2id = 4        // Recommended - current best practice
    }

    public class PasswordHashResult
    {
        public bool IsValid { get; set; }
        public bool NeedsRehash { get; set; }
        public HashAlgorithmType DetectedAlgorithm { get; set; }
    }

    public class ProductionPasswordService
    {
        private readonly PasswordHashingOptions _options;
        private readonly ILogger<ProductionPasswordService> _logger;
        private const string Argon2Prefix = "$argon2id$";
        private const string PBKDF2Prefix = "$pbkdf2$";

        public ProductionPasswordService(
            IOptions<PasswordHashingOptions> options,
            ILogger<ProductionPasswordService> logger)
        {
            _options = options.Value;
            _logger = logger;
        }

        /// <summary>
        /// Hash password using Argon2id - the current gold standard
        /// </summary>
        public async Task<string> HashPasswordAsync(string password)
        {
            if (string.IsNullOrEmpty(password))
                throw new ArgumentNullException(nameof(password));

            byte[] salt = RandomNumberGenerator.GetBytes(_options.SaltSize);

            using var argon2 = new Argon2id(System.Text.Encoding.UTF8.GetBytes(password))
            {
                Salt = salt,
                DegreeOfParallelism = _options.Argon2Parallelism,
                MemorySize = _options.Argon2MemorySize,
                Iterations = _options.Argon2Iterations
            };

            byte[] hash = await argon2.GetBytesAsync(_options.HashSize);

            // Format: $argon2id$v=19$m=65536,t=4,p=4$<salt>$<hash>
            string result = $"{Argon2Prefix}v=19$m={_options.Argon2MemorySize},t={_options.Argon2Iterations},p={_options.Argon2Parallelism}${Convert.ToBase64String(salt)}${Convert.ToBase64String(hash)}";

            _logger.LogDebug("Password hashed using Argon2id");
            return result;
        }

        /// <summary>
        /// Verify password and detect if rehashing is needed
        /// </summary>
        public async Task<PasswordHashResult> VerifyPasswordAsync(string password, string storedHash)
        {
            if (string.IsNullOrEmpty(password) || string.IsNullOrEmpty(storedHash))
            {
                return new PasswordHashResult { IsValid = false, NeedsRehash = false };
            }

            try
            {
                var algorithm = DetectAlgorithm(storedHash);
                bool isValid = algorithm switch
                {
                    HashAlgorithmType.Argon2id => await VerifyArgon2Async(password, storedHash),
                    HashAlgorithmType.PBKDF2 => VerifyPBKDF2(password, storedHash),
                    HashAlgorithmType.MD5Legacy => VerifyMD5Legacy(password, storedHash),
                    HashAlgorithmType.SHA256Legacy => VerifySHA256Legacy(password, storedHash),
                    _ => false
                };

                bool needsRehash = algorithm != HashAlgorithmType.Argon2id || 
                                   NeedsParameterUpgrade(storedHash);

                if (isValid && algorithm != HashAlgorithmType.Argon2id)
                {
                    _logger.LogWarning(
                        "User authenticated with legacy {Algorithm} hash - migration required",
                        algorithm);
                }

                return new PasswordHashResult
                {
                    IsValid = isValid,
                    NeedsRehash = isValid && needsRehash,
                    DetectedAlgorithm = algorithm
                };
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Password verification failed");
                return new PasswordHashResult { IsValid = false, NeedsRehash = false };
            }
        }

        private HashAlgorithmType DetectAlgorithm(string hash)
        {
            if (hash.StartsWith(Argon2Prefix))
                return HashAlgorithmType.Argon2id;
            if (hash.StartsWith(PBKDF2Prefix))
                return HashAlgorithmType.PBKDF2;
            if (hash.Length == 32) // 128-bit hex
                return HashAlgorithmType.MD5Legacy;
            if (hash.Length == 64) // 256-bit hex
                return HashAlgorithmType.SHA256Legacy;
            return HashAlgorithmType.Unknown;
        }

        private async Task<bool> VerifyArgon2Async(string password, string storedHash)
        {
            // Parse: $argon2id$v=19$m=65536,t=4,p=4$<salt>$<hash>
            var parts = storedHash.Split('$');
            if (parts.Length != 6) return false;

            var paramString = parts[3];
            var paramPairs = paramString.Split(',');

            int memory = int.Parse(paramPairs[0].Substring(2));
            int iterations = int.Parse(paramPairs[1].Substring(2));
            int parallelism = int.Parse(paramPairs[2].Substring(2));

            byte[] salt = Convert.FromBase64String(parts[4]);
            byte[] expectedHash = Convert.FromBase64String(parts[5]);

            using var argon2 = new Argon2id(System.Text.Encoding.UTF8.GetBytes(password))
            {
                Salt = salt,
                DegreeOfParallelism = parallelism,
                MemorySize = memory,
                Iterations = iterations
            };

            byte[] computedHash = await argon2.GetBytesAsync(expectedHash.Length);
            return CryptographicOperations.FixedTimeEquals(computedHash, expectedHash);
        }

        private bool VerifyPBKDF2(string password, string storedHash)
        {
            // Parse: $pbkdf2$<iterations>$<salt>$<hash>
            var parts = storedHash.Split('$');
            if (parts.Length != 5) return false;

            int iterations = int.Parse(parts[2]);
            byte[] salt = Convert.FromBase64String(parts[3]);
            byte[] expectedHash = Convert.FromBase64String(parts[4]);

            byte[] computedHash = Rfc2898DeriveBytes.Pbkdf2(
                password,
                salt,
                iterations,
                HashAlgorithmName.SHA256,
                expectedHash.Length
            );

            return CryptographicOperations.FixedTimeEquals(computedHash, expectedHash);
        }

        // Legacy verification - ONLY for migration, not new passwords!
        private bool VerifyMD5Legacy(string password, string storedHash)
        {
            using var md5 = MD5.Create();
            byte[] hash = md5.ComputeHash(System.Text.Encoding.UTF8.GetBytes(password));
            string computed = Convert.ToHexString(hash).ToLowerInvariant();
            return CryptographicOperations.FixedTimeEquals(
                System.Text.Encoding.UTF8.GetBytes(computed),
                System.Text.Encoding.UTF8.GetBytes(storedHash.ToLowerInvariant()));
        }

        private bool VerifySHA256Legacy(string password, string storedHash)
        {
            using var sha256 = SHA256.Create();
            byte[] hash = sha256.ComputeHash(System.Text.Encoding.UTF8.GetBytes(password));
            string computed = Convert.ToHexString(hash).ToLowerInvariant();
            return CryptographicOperations.FixedTimeEquals(
                System.Text.Encoding.UTF8.GetBytes(computed),
                System.Text.Encoding.UTF8.GetBytes(storedHash.ToLowerInvariant()));
        }

        private bool NeedsParameterUpgrade(string hash)
        {
            if (!hash.StartsWith(Argon2Prefix)) return true;

            // Check if memory/iterations are below current minimums
            var parts = hash.Split('$');
            if (parts.Length < 4) return true;

            var paramPairs = parts[3].Split(',');
            int memory = int.Parse(paramPairs[0].Substring(2));
            int iterations = int.Parse(paramPairs[1].Substring(2));

            return memory < _options.Argon2MemorySize || 
                   iterations < _options.Argon2Iterations;
        }
    }

    // Controller demonstrating transparent hash migration
    [ApiController]
    [Route("api/[controller]")]
    public class AuthController : ControllerBase
    {
        private readonly ProductionPasswordService _passwordService;
        private readonly IUserRepository _userRepository;
        private readonly ILogger<AuthController> _logger;

        public AuthController(
            ProductionPasswordService passwordService,
            IUserRepository userRepository,
            ILogger<AuthController> logger)
        {
            _passwordService = passwordService;
            _userRepository = userRepository;
            _logger = logger;
        }

        [HttpPost("login")]
        public async Task<IActionResult> Login([FromBody] LoginRequest request)
        {
            var user = await _userRepository.GetByEmailAsync(request.Email);
            if (user == null)
            {
                // Constant-time delay to prevent user enumeration
                await Task.Delay(TimeSpan.FromMilliseconds(Random.Shared.Next(100, 300)));
                return Unauthorized(new { message = "Invalid credentials" });
            }

            var result = await _passwordService.VerifyPasswordAsync(
                request.Password, 
                user.PasswordHash);

            if (!result.IsValid)
            {
                _logger.LogWarning(
                    "Failed login attempt for user {UserId} from {IP}",
                    user.Id, 
                    HttpContext.Connection.RemoteIpAddress);
                return Unauthorized(new { message = "Invalid credentials" });
            }

            // Transparent hash upgrade on successful login
            if (result.NeedsRehash)
            {
                _logger.LogInformation(
                    "Upgrading password hash for user {UserId} from {Algorithm} to Argon2id",
                    user.Id,
