  windowMs: 15 * 60 * 1000,    // 15 minutes
  max: 5,                       // 5 attempts per window
  message: { error: 'Too many login attempts, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Hash type identifiers for migration
const HASH_TYPES = {
  MD5: 'md5',
  SHA1: 'sha1',
  SHA256: 'sha256',
  BCRYPT: 'bcrypt',
  ARGON2: 'argon2'
};

// Detect hash type from stored hash
function detectHashType(storedHash) {
  if (storedHash.startsWith('$argon2')) return HASH_TYPES.ARGON2;
  if (storedHash.startsWith('$2a$') || storedHash.startsWith('$2b$')) return HASH_TYPES.BCRYPT;
  if (storedHash.length === 32) return HASH_TYPES.MD5;    // 128-bit = 32 hex chars
  if (storedHash.length === 40) return HASH_TYPES.SHA1;   // 160-bit = 40 hex chars
  if (storedHash.length === 64) return HASH_TYPES.SHA256; // 256-bit = 64 hex chars
  return null;
}

// Verify legacy hash (for migration)
function verifyLegacyHash(password, storedHash, hashType) {
  let computedHash;
  switch (hashType) {
    case HASH_TYPES.MD5:
      computedHash = crypto.createHash('md5').update(password).digest('hex');
      break;
    case HASH_TYPES.SHA1:
      computedHash = crypto.createHash('sha1').update(password).digest('hex');
      break;
    case HASH_TYPES.SHA256:
      computedHash = crypto.createHash('sha256').update(password).digest('hex');
      break;
    default:
      return false;
  }
  // Timing-safe comparison
  return crypto.timingSafeEqual(
    Buffer.from(computedHash, 'hex'),
    Buffer.from(storedHash, 'hex')
  );
}

// Secure password hashing with Argon2id
async function hashPasswordSecure(password) {
  return await argon2.hash(password, ARGON2_OPTIONS);
}

// Verify password with automatic migration
async function verifyAndMigratePassword(userId, password, storedHash) {
  const hashType = detectHashType(storedHash);

  if (!hashType) {
    console.error(`Unknown hash type for user ${userId}`);
    return { valid: false, needsMigration: false };
  }

  let isValid = false;
  let needsMigration = false;

  // Verify based on hash type
  if (hashType === HASH_TYPES.ARGON2) {
    isValid = await argon2.verify(storedHash, password);

    // Check if Argon2 parameters need updating
    if (isValid && argon2.needsRehash(storedHash, ARGON2_OPTIONS)) {
      needsMigration = true;
    }
  } else if (hashType === HASH_TYPES.BCRYPT) {
    const bcrypt = require('bcrypt');
    isValid = await bcrypt.compare(password, storedHash);
    needsMigration = true; // Upgrade bcrypt to Argon2
  } else {
    // Legacy MD5/SHA1/SHA256
    isValid = verifyLegacyHash(password, storedHash, hashType);
    needsMigration = true;
  }

  return { valid: isValid, needsMigration, oldHashType: hashType };
}

