import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;

public class SecurePasswordStorage {

    // BCrypt with strength 12 (2^12 = 4096 iterations)
    private static final int BCRYPT_STRENGTH = 12;
    private final PasswordEncoder passwordEncoder;

    public SecurePasswordStorage() {
        this.passwordEncoder = new BCryptPasswordEncoder(BCRYPT_STRENGTH);
    }

    /**
     * Hash password using BCrypt with automatic salt generation.
     * BCrypt is intentionally slow, taking ~250ms per hash at strength 12.
     */
    public String hashPassword(String password) {
        if (password == null || password.length() < 8) {
            throw new IllegalArgumentException("Password must be at least 8 characters");
        }
        // BCrypt automatically generates and embeds a unique salt
        return passwordEncoder.encode(password);
