**PRODUCTION PATTERN**:

```java
import de.mkammerer.argon2.Argon2;
import de.mkammerer.argon2.Argon2Factory;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.regex.Pattern;

public class ProductionPasswordService {

    private static final Logger logger = LoggerFactory.getLogger(ProductionPasswordService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    // Argon2id parameters (OWASP recommended)
    private static final int ARGON2_MEMORY_KB = 65536;  // 64 MB
    private static final int ARGON2_ITERATIONS = 3;
    private static final int ARGON2_PARALLELISM = 4;
    private static final int ARGON2_HASH_LENGTH = 32;

    // Hash format prefixes for identification
    private static final String ARGON2_PREFIX = "$argon2id$";
    private static final String BCRYPT_PREFIX = "$2a$";
    private static final Pattern MD5_PATTERN = Pattern.compile("^[a-f0-9]{32}$");
    private static final Pattern SHA256_PATTERN = Pattern.compile("^[a-f0-9]{64}$");

    private final Argon2 argon2;
    private final UserRepository userRepository;
    private final MetricsService metricsService;

    public ProductionPasswordService(UserRepository userRepository, 
                                      MetricsService metricsService) {
        this.argon2 = Argon2Factory.create(Argon2Factory.Argon2Types.ARGON2id);
        this.userRepository = userRepository;
        this.metricsService = metricsService;
    }

    /**
     * Hash new passwords with Argon2id - the current gold standard.
     */
    public String hashPassword(String password) {
        validatePasswordStrength(password);

        try {
            char[] passwordChars = password.toCharArray();
            String hash = argon2.hash(
                ARGON2_ITERATIONS,
                ARGON2_MEMORY_KB,
                ARGON2_PARALLELISM,
                passwordChars
            );
            // Immediately clear password from memory
            java.util.Arrays.fill(passwordChars, '\0');
            return hash;
        } catch (Exception e) {
            logger.error("Password hashing failed", e);
            throw new SecurityException("Password processing failed");
        }
    }

    /**
     * Verify password with automatic migration from legacy hashes.
     * Returns AuthResult with migration flag if rehashing is needed.
     */
    public AuthResult verifyAndMigrate(String userId, String rawPassword, 
                                        String storedHash) {
        if (rawPassword == null || storedHash == null) {
            auditLogger.warn("Null password or hash for user: {}", userId);
            return AuthResult.failure();
        }

        boolean verified = false;
        boolean needsMigration = false;
        String hashType = detectHashType(storedHash);

        try {
            switch (hashType) {
                case "ARGON2ID":
                    verified = argon2.verify(storedHash, rawPassword.toCharArray());
                    break;

                case "BCRYPT":
                    verified = verifyBcrypt(rawPassword, storedHash);
                    needsMigration = true;
                    break;

                case "SHA256":
                    verified = verifyLegacySha256(rawPassword, storedHash);
                    needsMigration = true;
                    metricsService.incrementCounter("legacy_sha256_login");
                    break;

                case "MD5":
                    verified = verifyLegacyMd5(rawPassword, storedHash);
                    needsMigration = true;
                    metricsService.incrementCounter("legacy_md5_login");
                    auditLogger.warn("MD5 hash detected for user: {}", userId);
                    break;

                default:
                    logger.error("Unknown hash format for user: {}", userId);
                    return AuthResult.failure();
            }

            if (verified && needsMigration) {
                migratePasswordHash(userId, rawPassword, hashType);
            }

            return verified ? AuthResult.success(needsMigration) : AuthResult.failure();

        } catch (Exception e) {
            logger.error("Password verification error for user: {}", userId, e);
            return AuthResult.failure();
        }
    }

    /**
     * Transparently upgrade legacy hash to Argon2id on successful login.
     */
    private void migratePasswordHash(String userId, String rawPassword, 
                                      String oldHashType) {
        try {
            String newHash = hashPassword(rawPassword);
            userRepository.updatePasswordHash(userId, newHash);

            auditLogger.info("Password hash migrated from {} to Argon2id for user: {}", 
                           oldHashType, userId);
            metricsService.incrementCounter("password_hash_migrations");

        } catch (Exception e) {
            // Log but don't fail authentication - migration is opportunistic
            logger.error("Failed to migrate password hash for user: {}", userId, e);
        }
    }

    private String detectHashType(String hash) {
        if (hash.startsWith(ARGON2_PREFIX)) return "ARGON2ID";
        if (hash.startsWith(BCRYPT_PREFIX)) return "BCRYPT";
        if (SHA256_PATTERN.matcher(hash).matches()) return "SHA256";
        if (MD5_PATTERN.matcher(hash).matches()) return "MD5";
        return "UNKNOWN";
    }

    private boolean verifyBcrypt(String password, String hash) {
        org.springframework.security.crypto.bcrypt.BCrypt bcrypt = 
            new org.springframework.security.crypto.bcrypt.BCrypt();
        return org.springframework.security.crypto.bcrypt.BCrypt
            .checkpw(password, hash);
    }

    private boolean verifyLegacySha256(String password, String storedHash) 
            throws NoSuchAlgorithmException {
        MessageDigest md = MessageDigest.getInstance("SHA-256");
        byte[] hash = md.digest(password.getBytes());
        String computed = bytesToHex(hash);
        return MessageDigest.isEqual(
            computed.getBytes(), 
            storedHash.toLowerCase().getBytes()
        );
    }

    private boolean verifyLegacyMd5(String password, String storedHash) 
            throws NoSuchAlgorithmException {
        MessageDigest md = MessageDigest.getInstance("MD5");
        byte[] hash = md.digest(password.getBytes());
        String computed = bytesToHex(hash);
        return MessageDigest.isEqual(
            computed.getBytes(), 
            storedHash.toLowerCase().getBytes()
